30	PERIOD_MAP = {
31	    "1W": ("5d",  "1h"),
32	    "1M": ("1mo", "1d"),
33	    "3M": ("3mo", "1d"),
34	    "6M": ("6mo", "1d"),
35	    "1Y": ("1y",  "1wk"),
