39	@app.route("/api/prices")
40	def api_prices():
41	    results = []
42	    for s in STOCKS:
43	        try:
44	            info = yf.Ticker(s["ticker"]).fast_info
45	            price = round(info.last_price, 2) if info.last_price else None
46	            prev  = info.previous_close
47	            if price and prev:
48	                change     = round(price - prev, 2)
49	                change_pct = round((change / prev) * 100, 2)
50	                positive   = change >= 0
51	            else:
52	                change = change_pct = None
53	                positive = None
54	        except:
55	            price = change = change_pct = None
56	            positive = None
57	        results.append({**s, "price": price, "change": change,
58	                        "change_pct": change_pct, "positive": positive})
59	    return jsonify(results)
