110	def load_marr():
111	    try:
112	        import csv
113	        rows = []
114	        with open("marr_data.csv", encoding="utf-8-sig") as f:
115	            for i, row in enumerate(csv.DictReader(f)):
116	                if i >= 30: break
117	                rows.append(dict(row))
118	        return rows
119	    except:
120	        return []
