224	<main>
225	
226	  <!-- PRICE CARDS -->
227	  <section>
228	    <div class="section-title">Market Overview</div>
229	    <div class="cards-grid" id="cardsGrid">
230	      {% for s in stocks %}
231	      <div class="price-card" id="card-{{ loop.index0 }}" onclick="selectStock('{{ s.ticker }}','{{ s.name }}',{{ loop.index0 }})">
