241	
242	  <!-- MAIN CHART -->
243	  <section>
244	    <div class="section-title">Chart</div>
245	    <div class="main-chart-box">
246	      <div class="chart-header">
247	        <div>
248	          <div class="chart-title" id="chartTitle">Nikkei 225</div>
249	          <div class="chart-subtitle" id="chartSubtitle">Loading...</div>
