322	<script>
323	const STOCKS = {{ stocks_js|safe }};
324	let currentTicker = "^N225";
325	let currentPeriod = "1M";
326	let activeCardIdx = 0;
327	let mainChartObj = null;
328	const miniCharts = {};
329	
330	// ── Colours ─────────────────────────────────────────────
331	function lineColor(positive){ return positive ? "#3fb950" : "#f85149"; }
332	function fillColor(positive){ return positive ? "rgba(63,185,80,.12)" : "rgba(248,81,73,.12)"; }
333	
334	// ── Main chart ───────────────────────────────────────────
335	async function loadMainChart(ticker, period){
336	  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/${period}`);
337	  if(!res.ok) return;
338	  const d = await res.json();
339	  if(d.error) return;
340	
341	  const color = lineColor(d.positive);
342	  const fill  = fillColor(d.positive);
343	  const sign  = d.positive ? "+" : "";
344	  document.getElementById("chartSubtitle").textContent =
345	    `${period}  ${sign}${d.change_pct}%`;
346	
347	  const ctx = document.getElementById("mainChart").getContext("2d");
348	  if(mainChartObj) mainChartObj.destroy();
349	  mainChartObj = new Chart(ctx, {
350	    type: "line",
351	    data: {
352	      labels: d.labels,
353	      datasets:[{
354	        data: d.prices,
355	        borderColor: color,
356	        backgroundColor: fill,
357	        borderWidth: 2,
358	        pointRadius: 0,
359	        fill: true,
360	        tension: 0.3
361	      }]
362	    },
363	    options:{
364	      responsive:true, maintainAspectRatio:false,
365	      interaction:{mode:"index",intersect:false},
366	      plugins:{
367	        legend:{display:false},
368	        tooltip:{
369	          backgroundColor:"#161b22",
370	          borderColor:"#30363d",
371	          borderWidth:1,
372	          titleColor:"#8b949e",
373	          bodyColor:"#f0f6fc",
374	          padding:10,
375	          callbacks:{
376	            label: ctx => " " + ctx.parsed.y.toLocaleString()
377	          }
378	        }
379	      },
380	      scales:{
381	        x:{
382	          grid:{color:"#161b22"},
383	          ticks:{color:"#484f58",maxTicksLimit:8,font:{size:11}},
384	          border:{color:"#21262d"}
385	        },
386	        y:{
387	          grid:{color:"#161b22"},
388	          ticks:{color:"#484f58",font:{size:11},callback:v=>v.toLocaleString()},
389	          border:{color:"#21262d"},
390	          position:"right"
391	        }
392	      }
393	    }
394	  });
395	}
396	
397	// ── Mini sparkline ───────────────────────────────────────
398	async function loadMiniChart(ticker, idx, positive){
399	  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/1M`);
400	  if(!res.ok) return;
401	  const d = await res.json();
402	  if(d.error || !d.prices) return;
403	
404	  const isPos = d.positive;
405	  const color = lineColor(isPos);
406	  const ctx = document.getElementById(`mini-${idx}`).getContext("2d");
407	  if(miniCharts[idx]) miniCharts[idx].destroy();
408	  miniCharts[idx] = new Chart(ctx, {
409	    type:"line",
410	    data:{
411	      labels: d.labels,
412	      datasets:[{data:d.prices,borderColor:color,borderWidth:1.5,
413	                 pointRadius:0,fill:false,tension:0.3}]
414	    },
415	    options:{
416	      responsive:true,maintainAspectRatio:false,
417	      plugins:{legend:{display:false},tooltip:{enabled:false}},
418	      scales:{x:{display:false},y:{display:false}},
419	      animation:{duration:400}
420	    }
421	  });
422	}
423	
424	// ── Prices ───────────────────────────────────────────────
425	async function loadPrices(){
426	  const res = await fetch("/api/prices");
427	  const data = await res.json();
428	  const now = new Date().toLocaleTimeString("ja-JP");
429	  document.getElementById("lastUpdated").textContent = "Last updated: " + now;
430	
431	  data.forEach((s,i) => {
432	    const priceEl  = document.getElementById(`price-${i}`);
433	    const changeEl = document.getElementById(`change-${i}`);
434	    if(!priceEl) return;
435	
436	    if(s.price !== null){
437	      priceEl.textContent = s.price.toLocaleString();
438	      if(s.change !== null){
439	        const sign = s.positive ? "+" : "";
440	        changeEl.textContent = `${sign}${s.change} (${sign}${s.change_pct}%)`;
441	        changeEl.className = "card-change " + (s.positive ? "up" : "down");
442	        priceEl.className  = "card-price "  + (s.positive ? "up" : "down");
443	      }
444	    } else {
445	      priceEl.textContent  = "N/A";
446	      changeEl.textContent = "—";
447	    }
448	
449	    // load mini chart async
450	    setTimeout(() => loadMiniChart(s.ticker, i, s.positive), i * 120);
451	  });
452	}
453	
454	// ── Stock selection ──────────────────────────────────────
455	function selectStock(ticker, name, idx){
456	  document.querySelectorAll(".price-card").forEach(c=>c.classList.remove("active"));
457	  document.getElementById(`card-${idx}`).classList.add("active");
458	  document.getElementById("chartTitle").textContent = name;
459	  currentTicker = ticker;
460	  activeCardIdx = idx;
461	  loadMainChart(ticker, currentPeriod);
462	}
463	
464	// ── Period toggle ────────────────────────────────────────
465	function setPeriod(p){
466	  currentPeriod = p;
467	  document.querySelectorAll(".period-btn").forEach(b=>{
468	    b.classList.toggle("active", b.textContent===p);
469	  });
470	  loadMainChart(currentTicker, currentPeriod);
471	}
472	
473	// ── Init ─────────────────────────────────────────────────
474	document.getElementById("card-0").classList.add("active");
475	loadPrices();
476	loadMainChart("^N225","1M");
477	</script>
478	</body>
479	</html>"""
480	
481	@app.route("/")
482	def index():
483	    import json
484	    news  = fetch_news()
485	    marr  = load_marr()
486	    stocks_js = json.dumps([{"ticker":s["ticker"],"name":s["name"]} for s in STOCKS])
