from flask import Flask, render_template_string, jsonify
import yfinance as yf
import requests
import xml.etree.ElementTree as ET
import re
from datetime import datetime

app = Flask(__name__)

STOCKS = [
    {"ticker": "^N225",   "name": "Nikkei 225",       "type": "index"},
    {"ticker": "1306.T",  "name": "TOPIX ETF",         "type": "index"},
    {"ticker": "JPY=X",   "name": "USD/JPY",           "type": "fx"},
    {"ticker": "^TNX",    "name": "US 10Y Yield",      "type": "bond"},
    {"ticker": "7203.T",  "name": "Toyota",            "type": "stock"},
    {"ticker": "6758.T",  "name": "Sony",              "type": "stock"},
    {"ticker": "9984.T",  "name": "SoftBank",          "type": "stock"},
    {"ticker": "8306.T",  "name": "Mitsubishi UFJ",    "type": "stock"},
    {"ticker": "6861.T",  "name": "Keyence",           "type": "stock"},
    {"ticker": "9432.T",  "name": "NTT",               "type": "stock"},
    {"ticker": "8035.T",  "name": "Tokyo Electron",    "type": "stock"},
]

NEWS_FEEDS = [
    ("https://feeds.content.dowjones.io/public/rss/mw_realtimeheadlines", "MarketWatch"),
    ("https://www.reutersagency.com/feed/?best-topics=business-finance&post_type=best", "Reuters"),
    ("https://feeds.bbci.co.uk/news/business/rss.xml", "BBC Business"),
]

PERIOD_MAP = {
    "1W": ("5d",  "1h"),
    "1M": ("1mo", "1d"),
    "3M": ("3mo", "1d"),
    "6M": ("6mo", "1d"),
    "1Y": ("1y",  "1wk"),
    "5Y": ("5y",  "1wk"),
}

@app.route("/api/prices")
def api_prices():
    results = []
    for s in STOCKS:
        try:
            info = yf.Ticker(s["ticker"]).fast_info
            price = round(info.last_price, 2) if info.last_price else None
            prev  = info.previous_close
            if price and prev:
                change     = round(price - prev, 2)
                change_pct = round((change / prev) * 100, 2)
                positive   = change >= 0
            else:
                change = change_pct = None
                positive = None
        except:
            price = change = change_pct = None
            positive = None
        results.append({**s, "price": price, "change": change,
                        "change_pct": change_pct, "positive": positive})
    return jsonify(results)

@app.route("/api/chart/<path:ticker>/<period>")
def api_chart(ticker, period):
    yf_period, interval = PERIOD_MAP.get(period, ("1mo", "1d"))
    try:
        hist = yf.Ticker(ticker).history(period=yf_period, interval=interval)
        if hist.empty:
            return jsonify({"error": "No data"}), 404
        fmt = "%b %d %H:%M" if interval in ["5m","30m","1h"] else "%b %d"
        labels = [idx.strftime(fmt) for idx in hist.index]
        prices = [round(p, 2) for p in hist["Close"].tolist()]
        first, last = prices[0], prices[-1]
        change_pct = round(((last - first) / first) * 100, 2) if first else 0
        return jsonify({"labels": labels, "prices": prices, "change_pct": change_pct,
                        "positive": change_pct >= 0})
    except Exception as e:
        return jsonify({"error": str(e)}), 500

def get_image(item):
    for ns in ["http://search.yahoo.com/mrss/", "http://www.w3.org/2005/Atom"]:
        mc = item.find(f"{{{ns}}}content")
        if mc is not None and mc.get("url"):
            return mc.get("url")
        mc = item.find(f"{{{ns}}}thumbnail")
        if mc is not None and mc.get("url"):
            return mc.get("url")
    enc = item.find("enclosure")
    if enc is not None and "image" in enc.get("type",""):
        return enc.get("url")
    return None

def fetch_news():
    articles = []
    for url, source in NEWS_FEEDS:
        try:
            r = requests.get(url, timeout=8, headers={"User-Agent": "Mozilla/5.0"})
            root = ET.fromstring(r.content)
            for item in root.findall(".//item")[:7]:
                title = item.findtext("title","").strip()
                link  = item.findtext("link","").strip()
                pub   = item.findtext("pubDate","").strip()[:25]
                desc  = re.sub("<[^<]+?>","", item.findtext("description",""))[:220].strip()
                img   = get_image(item)
                if title and link:
                    articles.append({"title":title,"link":link,"pub":pub,
                                     "source":source,"desc":desc,"img":img})
        except:
            continue
    return articles

def load_marr():
    try:
        import csv
        rows = []
        with open("marr_data.csv", encoding="utf-8-sig") as f:
            for i, row in enumerate(csv.DictReader(f)):
                if i >= 30: break
                rows.append(dict(row))
        return rows
    except:
        return []

HTML = r"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>Japan Market Dashboard</title>
<script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.0/dist/chart.umd.min.js"></script>
<style>
*{margin:0;padding:0;box-sizing:border-box}
body{background:#080c14;color:#e2e8f0;font-family:'Segoe UI',system-ui,sans-serif;min-height:100vh}
::-webkit-scrollbar{width:6px;background:#0d1117}
::-webkit-scrollbar-thumb{background:#30363d;border-radius:3px}

/* HEADER */
header{background:linear-gradient(135deg,#0d1117 0%,#161b22 100%);border-bottom:1px solid #21262d;padding:18px 32px;display:flex;align-items:center;justify-content:space-between}
header h1{font-size:20px;font-weight:700;background:linear-gradient(90deg,#58a6ff,#a5d6ff);-webkit-background-clip:text;-webkit-text-fill-color:transparent}
.header-sub{font-size:12px;color:#484f58;margin-top:2px}
.refresh-btn{background:#21262d;border:1px solid #30363d;color:#8b949e;padding:6px 14px;border-radius:6px;cursor:pointer;font-size:12px;transition:.2s}
.refresh-btn:hover{background:#30363d;color:#e2e8f0}

main{padding:28px 32px;max-width:1600px;margin:0 auto}
section{margin-bottom:40px}
.section-title{font-size:11px;font-weight:700;color:#484f58;text-transform:uppercase;letter-spacing:1.5px;margin-bottom:16px;display:flex;align-items:center;gap:8px}
.section-title::after{content:'';flex:1;height:1px;background:#21262d}

/* PRICE CARDS */
.cards-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(160px,1fr));gap:12px}
.price-card{background:#0d1117;border:1px solid #21262d;border-radius:10px;padding:14px;cursor:pointer;transition:.15s;position:relative;overflow:hidden}
.price-card:hover{border-color:#30363d;background:#161b22;transform:translateY(-1px)}
.price-card.active{border-color:#58a6ff;background:#0d1117}
.card-name{font-size:12px;color:#8b949e;margin-bottom:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.card-ticker{font-size:10px;color:#30363d;margin-bottom:10px}
.card-price{font-size:18px;font-weight:700;color:#f0f6fc;margin-bottom:3px}
.card-change{font-size:12px}
.up{color:#3fb950}.down{color:#f85149}.neutral{color:#8b949e}
.mini-chart{height:42px;margin-top:8px}

/* MAIN CHART */
.main-chart-box{background:#0d1117;border:1px solid #21262d;border-radius:12px;padding:24px}
.chart-header{display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:20px;flex-wrap:wrap;gap:12px}
.chart-title{font-size:18px;font-weight:700;color:#f0f6fc}
.chart-subtitle{font-size:13px;color:#8b949e;margin-top:3px}
.period-btns{display:flex;gap:6px}
.period-btn{background:#161b22;border:1px solid #21262d;color:#8b949e;padding:5px 14px;border-radius:6px;cursor:pointer;font-size:12px;transition:.15s}
.period-btn:hover{border-color:#30363d;color:#e2e8f0}
.period-btn.active{background:#1f6feb;border-color:#1f6feb;color:#fff}
.chart-wrap{position:relative;height:300px}

/* NEWS */
.featured-grid{display:grid;grid-template-columns:1fr 1fr;gap:16px;margin-bottom:16px}
.news-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:12px}

.news-card{background:#0d1117;border:1px solid #21262d;border-radius:10px;overflow:hidden;transition:.15s;display:flex;flex-direction:column}
.news-card:hover{border-color:#30363d;transform:translateY(-2px)}
.news-card a{text-decoration:none;color:inherit;display:flex;flex-direction:column;height:100%}

.news-img{width:100%;object-fit:cover;background:linear-gradient(135deg,#161b22,#21262d)}
.featured .news-img{height:200px}
.news-card:not(.featured) .news-img{height:130px}

.news-img-placeholder{display:flex;align-items:center;justify-content:center;font-size:28px}
.featured .news-img-placeholder{height:200px}
.news-card:not(.featured) .news-img-placeholder{height:130px}

.news-body{padding:14px;flex:1;display:flex;flex-direction:column;gap:6px}
.news-source{font-size:10px;font-weight:700;color:#58a6ff;text-transform:uppercase;letter-spacing:.8px}
.featured .news-title{font-size:16px;font-weight:700;color:#f0f6fc;line-height:1.4}
.news-card:not(.featured) .news-title{font-size:13px;font-weight:600;color:#e2e8f0;line-height:1.4}
.news-desc{font-size:12px;color:#8b949e;line-height:1.6;margin-top:4px;flex:1}
.news-card:not(.featured) .news-desc{display:none}
.news-date{font-size:10px;color:#30363d;margin-top:auto;padding-top:8px}

/* MINI NEWS CHART */
.news-mini-chart{height:50px;padding:0 14px 10px}

/* MARR */
.marr-box{background:#0d1117;border:1px solid #21262d;border-radius:10px;padding:20px}
.marr-box p{color:#8b949e;font-size:13px;line-height:1.7}
.marr-box a{color:#58a6ff}
.marr-table{width:100%;border-collapse:collapse;font-size:12px;margin-top:16px}
.marr-table th{text-align:left;padding:8px 12px;border-bottom:1px solid #21262d;color:#484f58;font-weight:600;text-transform:uppercase;font-size:10px;letter-spacing:.8px}
.marr-table td{padding:8px 12px;border-bottom:1px solid #161b22;color:#c9d1d9}
.marr-table tr:hover td{background:#0d1117}

.loading{color:#484f58;font-size:13px;padding:12px 0}
@media(max-width:768px){
  main{padding:16px}
  .featured-grid{grid-template-columns:1fr}
  header{padding:14px 16px}
}
</style>
</head>
<body>

<header>
  <div>
    <h1>Japan Market Dashboard</h1>
    <div class="header-sub" id="lastUpdated">Loading...</div>
  </div>
  <button class="refresh-btn" onclick="location.reload()">⟳ Refresh</button>
</header>

<main>

  <!-- PRICE CARDS -->
  <section>
    <div class="section-title">Market Overview</div>
    <div class="cards-grid" id="cardsGrid">
      {% for s in stocks %}
      <div class="price-card" id="card-{{ loop.index0 }}" onclick="selectStock('{{ s.ticker }}','{{ s.name }}',{{ loop.index0 }})">
        <div class="card-name">{{ s.name }}</div>
        <div class="card-ticker">{{ s.ticker }}</div>
        <div class="card-price" id="price-{{ loop.index0 }}">—</div>
        <div class="card-change" id="change-{{ loop.index0 }}">—</div>
        <div class="mini-chart"><canvas id="mini-{{ loop.index0 }}"></canvas></div>
      </div>
      {% endfor %}
    </div>
  </section>

  <!-- MAIN CHART -->
  <section>
    <div class="section-title">Chart</div>
    <div class="main-chart-box">
      <div class="chart-header">
        <div>
          <div class="chart-title" id="chartTitle">Nikkei 225</div>
          <div class="chart-subtitle" id="chartSubtitle">Loading...</div>
        </div>
        <div class="period-btns">
          {% for p in ['1W','1M','3M','6M','1Y','5Y'] %}
          <button class="period-btn {% if p == '1M' %}active{% endif %}" onclick="setPeriod('{{ p }}')">{{ p }}</button>
          {% endfor %}
        </div>
      </div>
      <div class="chart-wrap"><canvas id="mainChart"></canvas></div>
    </div>
  </section>

  <!-- FEATURED NEWS -->
  <section>
    <div class="section-title">Featured News</div>
    <div class="featured-grid">
      {% for a in news[:2] %}
      <div class="news-card featured">
        <a href="{{ a.link }}" target="_blank" rel="noopener">
          {% if a.img %}
          <img class="news-img" src="{{ a.img }}" alt="" loading="lazy" onerror="this.parentNode.replaceChild(makePlaceholder('{{ a.source }}'),this)">
          {% else %}
          <div class="news-img news-img-placeholder">{{ {'MarketWatch':'📈','Reuters':'🌐','BBC Business':'📰'}.get(a.source,'📊') }}</div>
          {% endif %}
          <div class="news-body">
            <div class="news-source">{{ a.source }}</div>
            <div class="news-title">{{ a.title }}</div>
            <div class="news-desc">{{ a.desc }}</div>
            <div class="news-date">{{ a.pub }}</div>
          </div>
        </a>
      </div>
      {% endfor %}
    </div>

    <!-- SMALLER NEWS -->
    <div class="news-grid">
      {% for a in news[2:] %}
      <div class="news-card">
        <a href="{{ a.link }}" target="_blank" rel="noopener">
          {% if a.img %}
          <img class="news-img" src="{{ a.img }}" alt="" loading="lazy">
          {% else %}
          <div class="news-img news-img-placeholder" style="background:linear-gradient(135deg,#0d1f3c,#163366)">{{ {'MarketWatch':'📈','Reuters':'🌐','BBC Business':'📰'}.get(a.source,'📊') }}</div>
          {% endif %}
          <div class="news-body">
            <div class="news-source">{{ a.source }}</div>
            <div class="news-title">{{ a.title }}</div>
            <div class="news-date">{{ a.pub }}</div>
          </div>
        </a>
      </div>
      {% endfor %}
    </div>
  </section>

  <!-- MARR -->
  <section>
    <div class="section-title">MARR M&A Data</div>
    <div class="marr-box">
      {% if marr %}
      <table class="marr-table">
        <thead><tr>{% for col in marr[0].keys() %}<th>{{ col }}</th>{% endfor %}</tr></thead>
        <tbody>{% for row in marr %}<tr>{% for v in row.values() %}<td>{{ v }}</td>{% endfor %}</tr>{% endfor %}</tbody>
      </table>
      {% else %}
      <p>Export deal data from <a href="https://www.marr.jp" target="_blank">marr.jp</a> as CSV, save it as <strong>marr_data.csv</strong> in this folder, and it will appear here automatically.</p>
      {% endif %}
    </div>
  </section>

</main>

<script>
const STOCKS = {{ stocks_js|safe }};
let currentTicker = "^N225";
let currentPeriod = "1M";
let activeCardIdx = 0;
let mainChartObj = null;
const miniCharts = {};

// ── Colours ─────────────────────────────────────────────
function lineColor(positive){ return positive ? "#3fb950" : "#f85149"; }
function fillColor(positive){ return positive ? "rgba(63,185,80,.12)" : "rgba(248,81,73,.12)"; }

// ── Main chart ───────────────────────────────────────────
async function loadMainChart(ticker, period){
  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/${period}`);
  if(!res.ok) return;
  const d = await res.json();
  if(d.error) return;

  const color = lineColor(d.positive);
  const fill  = fillColor(d.positive);
  const sign  = d.positive ? "+" : "";
  document.getElementById("chartSubtitle").textContent =
    `${period}  ${sign}${d.change_pct}%`;

  const ctx = document.getElementById("mainChart").getContext("2d");
  if(mainChartObj) mainChartObj.destroy();
  mainChartObj = new Chart(ctx, {
    type: "line",
    data: {
      labels: d.labels,
      datasets:[{
        data: d.prices,
        borderColor: color,
        backgroundColor: fill,
        borderWidth: 2,
        pointRadius: 0,
        fill: true,
        tension: 0.3
      }]
    },
    options:{
      responsive:true, maintainAspectRatio:false,
      interaction:{mode:"index",intersect:false},
      plugins:{
        legend:{display:false},
        tooltip:{
          backgroundColor:"#161b22",
          borderColor:"#30363d",
          borderWidth:1,
          titleColor:"#8b949e",
          bodyColor:"#f0f6fc",
          padding:10,
          callbacks:{
            label: ctx => " " + ctx.parsed.y.toLocaleString()
          }
        }
      },
      scales:{
        x:{
          grid:{color:"#161b22"},
          ticks:{color:"#484f58",maxTicksLimit:8,font:{size:11}},
          border:{color:"#21262d"}
        },
        y:{
          grid:{color:"#161b22"},
          ticks:{color:"#484f58",font:{size:11},callback:v=>v.toLocaleString()},
          border:{color:"#21262d"},
          position:"right"
        }
      }
    }
  });
}

// ── Mini sparkline ───────────────────────────────────────
async function loadMiniChart(ticker, idx, positive){
  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/1M`);
  if(!res.ok) return;
  const d = await res.json();
  if(d.error || !d.prices) return;

  const isPos = d.positive;
  const color = lineColor(isPos);
  const ctx = document.getElementById(`mini-${idx}`).getContext("2d");
  if(miniCharts[idx]) miniCharts[idx].destroy();
  miniCharts[idx] = new Chart(ctx, {
    type:"line",
    data:{
      labels: d.labels,
      datasets:[{data:d.prices,borderColor:color,borderWidth:1.5,
                 pointRadius:0,fill:false,tension:0.3}]
    },
    options:{
      responsive:true,maintainAspectRatio:false,
      plugins:{legend:{display:false},tooltip:{enabled:false}},
      scales:{x:{display:false},y:{display:false}},
      animation:{duration:400}
    }
  });
}

// ── Prices ───────────────────────────────────────────────
async function loadPrices(){
  const res = await fetch("/api/prices");
  const data = await res.json();
  const now = new Date().toLocaleTimeString("ja-JP");
  document.getElementById("lastUpdated").textContent = "Last updated: " + now;

  data.forEach((s,i) => {
    const priceEl  = document.getElementById(`price-${i}`);
    const changeEl = document.getElementById(`change-${i}`);
    if(!priceEl) return;

    if(s.price !== null){
      priceEl.textContent = s.price.toLocaleString();
      if(s.change !== null){
        const sign = s.positive ? "+" : "";
        changeEl.textContent = `${sign}${s.change} (${sign}${s.change_pct}%)`;
        changeEl.className = "card-change " + (s.positive ? "up" : "down");
        priceEl.className  = "card-price "  + (s.positive ? "up" : "down");
      }
    } else {
      priceEl.textContent  = "N/A";
      changeEl.textContent = "—";
    }

    // load mini chart async
    setTimeout(() => loadMiniChart(s.ticker, i, s.positive), i * 120);
  });
}

// ── Stock selection ──────────────────────────────────────
function selectStock(ticker, name, idx){
  document.querySelectorAll(".price-card").forEach(c=>c.classList.remove("active"));
  document.getElementById(`card-${idx}`).classList.add("active");
  document.getElementById("chartTitle").textContent = name;
  currentTicker = ticker;
  activeCardIdx = idx;
  loadMainChart(ticker, currentPeriod);
}

// ── Period toggle ────────────────────────────────────────
function setPeriod(p){
  currentPeriod = p;
  document.querySelectorAll(".period-btn").forEach(b=>{
    b.classList.toggle("active", b.textContent===p);
  });
  loadMainChart(currentTicker, currentPeriod);
}

// ── Init ─────────────────────────────────────────────────
document.getElementById("card-0").classList.add("active");
loadPrices();
loadMainChart("^N225","1M");
</script>
</body>
</html>"""

@app.route("/")
def index():
    import json
    news  = fetch_news()
    marr  = load_marr()
    stocks_js = json.dumps([{"ticker":s["ticker"],"name":s["name"]} for s in STOCKS])
    return render_template_string(HTML, stocks=STOCKS, news=news, marr=marr, stocks_js=stocks_js)

if __name__ == "__main__":
    print("Dashboard running at http://127.0.0.1:5000")
    app.run(debug=False)

