<script>
const STOCKS = {{ stocks_js|safe }};
let currentTicker = "^N225";
let currentPeriod = "1M";
let activeCardIdx = 0;
let mainChartObj  = null;
const miniCharts  = {};

// ── Theme helpers ─────────────────────────────────────────
function isLight() { return document.body.classList.contains('light'); }

function chartTheme() {
  const l = isLight();
  return {
    grid:     l ? '#eaeef2' : '#161b22',
    tick:     l ? '#8c959f' : '#484f58',
    tipBg:    l ? '#ffffff' : '#161b22',
    tipBdr:   l ? '#d0d7de' : '#30363d',
    tipTitle: l ? '#57606a' : '#8b949e',
    tipBody:  l ? '#1f2328' : '#f0f6fc',
  };
}

function toggleTheme() {
  const light = document.getElementById('themeToggle').checked;
  document.body.classList.toggle('light', light);
  applyChartTheme();
}

function applyChartTheme() {
  if (!mainChartObj) return;
  const t  = chartTheme();
  const sc = mainChartObj.options.scales;
  sc.x.grid.color   = t.grid;
  sc.x.ticks.color  = t.tick;
  sc.x.border.color = t.tipBdr;
  sc.y.grid.color   = t.grid;
  sc.y.ticks.color  = t.tick;
  sc.y.border.color = t.tipBdr;
  const tp = mainChartObj.options.plugins.tooltip;
  tp.backgroundColor = t.tipBg;
  tp.borderColor     = t.tipBdr;
  tp.titleColor      = t.tipTitle;
  tp.bodyColor       = t.tipBody;
  mainChartObj.update();
}

// ── Colour helpers ────────────────────────────────────────
function lineColor(pos) { return pos ? '#3fb950' : '#f85149'; }
function fillColor(pos) { return pos ? 'rgba(63,185,80,.12)' : 'rgba(248,81,73,.12)'; }

// ── Main chart ────────────────────────────────────────────
async function loadMainChart(ticker, period) {
  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/${period}`);
  if (!res.ok) return;
  const d = await res.json();
  if (d.error) return;

  const color = lineColor(d.positive);
  const fill  = fillColor(d.positive);
  const sign  = d.positive ? '+' : '';
  const t     = chartTheme();

  document.getElementById('chartSubtitle').textContent =
    `${period}  ${sign}${d.change_pct}%`;

  const ctx = document.getElementById('mainChart').getContext('2d');
  if (mainChartObj) mainChartObj.destroy();
  mainChartObj = new Chart(ctx, {
    type: 'line',
    data: {
      labels: d.labels,
      datasets: [{
        data: d.prices,
        borderColor: color,
        backgroundColor: fill,
        borderWidth: 2,
        pointRadius: 0,
        fill: true,
        tension: 0.3
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: { display: false },
        tooltip: {
          backgroundColor: t.tipBg,
          borderColor:     t.tipBdr,
          borderWidth:     1,
          titleColor:      t.tipTitle,
          bodyColor:       t.tipBody,
          padding:         10,
          callbacks: { label: c => ' ' + c.parsed.y.toLocaleString() }
        }
      },
      scales: {
        x: {
          grid:   { color: t.grid },
          ticks:  { color: t.tick, maxTicksLimit: 8, font: { size: 11 } },
          border: { color: t.tipBdr }
        },
        y: {
          grid:     { color: t.grid },
          ticks:    { color: t.tick, font: { size: 11 }, callback: v => v.toLocaleString() },
          border:   { color: t.tipBdr },
          position: 'right'
        }
      }
    }
  });
}

// ── Mini sparkline ────────────────────────────────────────
async function loadMiniChart(ticker, idx) {
  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/1M`);
  if (!res.ok) return;
  const d = await res.json();
  if (d.error || !d.prices) return;

  const color = lineColor(d.positive);
  const ctx   = document.getElementById(`mini-${idx}`).getContext('2d');
  if (miniCharts[idx]) miniCharts[idx].destroy();
  miniCharts[idx] = new Chart(ctx, {
    type: 'line',
    data: {
      labels: d.labels,
      datasets: [{ data: d.prices, borderColor: color, borderWidth: 1.5,
                   pointRadius: 0, fill: false, tension: 0.3 }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: false }, tooltip: { enabled: false } },
      scales:  { x: { display: false }, y: { display: false } },
      animation: { duration: 400 }
    }
  });
}

// ── Prices ────────────────────────────────────────────────
async function loadPrices() {
  const res  = await fetch('/api/prices');
