}

*  { margin:0; padding:0; box-sizing:border-box }
body {
  background: var(--bg-base);
  color: var(--text-main);
  font-family: 'Hiragino Sans','Yu Gothic','Meiryo','Segoe UI',system-ui,sans-serif;
  height: 100vh;
  display: flex;
  flex-direction: column;
  overflow: hidden;
  transition: background .2s, color .2s;
}
::-webkit-scrollbar { width:6px; background: var(--sb-bg) }
::-webkit-scrollbar-thumb { background: var(--sb-thumb); border-radius:3px }

/* ── HEADER ─────────────────────────────────────────────── */
header {
  background: linear-gradient(135deg, var(--bg-hdr1) 0%, var(--bg-hdr2) 100%);
  border-bottom: 1px solid var(--border-dim);
  padding: 13px 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-shrink: 0;
  transition: background .2s, border-color .2s;
}
header h1 {
  font-size: 18px;
  font-weight: 700;
  background: linear-gradient(90deg, var(--accent), #a5d6ff);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.header-sub { font-size: 11px; color: var(--text-dim); margin-top: 2px }
.header-right { display: flex; align-items: center; gap: 12px }

.refresh-btn {
  background: var(--bg-card);
  border: 1px solid var(--border-mid);
  color: var(--text-sub);
  padding: 5px 12px;
  border-radius: 6px;
  cursor: pointer;
  font-size: 12px;
  transition: .2s;
}
.refresh-btn:hover { background: var(--bg-hover); color: var(--text-main) }

/* ── THEME TOGGLE ────────────────────────────────────────── */
.theme-toggle {
  display: flex;
  align-items: center;
  gap: 7px;
  cursor: pointer;
  user-select: none;
  font-size: 12px;
  color: var(--text-sub);
}
.theme-toggle input { display: none }
.toggle-track {
  width: 36px;
  height: 20px;
  background: var(--border-mid);
  border-radius: 10px;
  position: relative;
  transition: background .2s;
  flex-shrink: 0;
}
.theme-toggle input:checked ~ .toggle-track { background: var(--accent-dark) }
.toggle-thumb {
  width: 14px;
  height: 14px;
  background: #fff;
  border-radius: 50%;
  position: absolute;
  top: 3px;
  left: 3px;
  transition: left .2s;
  pointer-events: none;
}
.theme-toggle input:checked ~ .toggle-track .toggle-thumb { left: 19px }

/* ── PAGE BODY ───────────────────────────────────────────── */
.page-body {
  display: grid;
  grid-template-columns: 1fr 1fr;
  flex: 1;
  overflow: hidden;
  min-height: 0;
}

/* ── LEFT PANEL ──────────────────────────────────────────── */
.left-panel {
  border-right: 1px solid var(--border-dim);
  overflow-y: auto;
  padding: 20px 22px;
  display: flex;
  flex-direction: column;
  gap: 22px;
}

/* ── RIGHT PANEL ─────────────────────────────────────────── */
.right-panel {
  display: grid;
  grid-template-rows: 1fr 1fr;
  overflow: hidden;
  min-height: 0;
}
.news-pane {
  overflow-y: auto;
  padding: 16px 20px;
  min-height: 0;
}
.news-pane:first-child { border-bottom: 1px solid var(--border-dim) }

/* ── SECTION TITLES ──────────────────────────────────────── */
.section-title {
  font-size: 10px;
  font-weight: 700;
  color: var(--text-dim);
  text-transform: uppercase;
  letter-spacing: 1.5px;
  margin-bottom: 12px;
  display: flex;
  align-items: center;
  gap: 8px;
}
.section-title::after { content:''; flex:1; height:1px; background: var(--border-dim) }

/* ── PRICE CARDS ─────────────────────────────────────────── */
.cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(148px, 1fr));
  gap: 10px;
}
.price-card {
  background: var(--bg-card);
  border: 1px solid var(--border-dim);
  border-radius: 10px;
  padding: 12px;
  cursor: pointer;
  transition: border-color .15s, background .15s, transform .15s;
  overflow: hidden;
}
.price-card:hover {
  border-color: var(--border-mid);
  background: var(--bg-hover);
  transform: translateY(-1px);
}
.price-card.active { border-color: var(--accent) }
.card-name {
  font-size: 11px;
  color: var(--text-sub);
  margin-bottom: 2px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}
.card-ticker { font-size: 10px; color: var(--border-mid); margin-bottom: 8px }
.card-price  { font-size: 17px; font-weight: 700; color: var(--text-head); margin-bottom: 2px }
.card-change { font-size: 11px }
.up      { color: var(--up) }
.down    { color: var(--down) }
.neutral { color: var(--text-sub) }
.mini-chart { height: 40px; margin-top: 6px }

/* ── MAIN CHART ──────────────────────────────────────────── */
.main-chart-box {
  background: var(--bg-card);
  border: 1px solid var(--border-dim);
  border-radius: 12px;
  padding: 20px;
  transition: background .2s, border-color .2s;
}
.chart-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  margin-bottom: 16px;
  flex-wrap: wrap;
  gap: 10px;
}
.chart-title    { font-size: 16px; font-weight: 700; color: var(--text-head) }
.chart-subtitle { font-size: 12px; color: var(--text-sub); margin-top: 3px }
.period-btns    { display: flex; gap: 5px; flex-wrap: wrap }
.period-btn {
  background: var(--bg-hover);
  border: 1px solid var(--border-dim);
  color: var(--text-sub);
  padding: 4px 11px;
  border-radius: 6px;
  cursor: pointer;
  font-size: 11px;
  transition: .15s;
}
.period-btn:hover { border-color: var(--border-mid); color: var(--text-main) }
.period-btn.active { background: var(--accent-dark); border-color: var(--accent-dark); color:#fff }
.chart-wrap { position:relative; height:250px }

/* ── NEWS CARDS ──────────────────────────────────────────── */
.news-list { display: flex; flex-direction: column; gap: 9px }
.news-card {
  background: var(--bg-card);
  border: 1px solid var(--border-dim);
  border-radius: 8px;
  overflow: hidden;
  transition: border-color .15s, transform .15s;
}
.news-card:hover { border-color: var(--border-mid); transform: translateY(-1px) }
.news-card a {
  text-decoration: none;
  color: inherit;
  display: flex;
  align-items: stretch;
}
.news-thumb {
  width: 88px;
  min-width: 88px;
  object-fit: cover;
  background: var(--bg-hover);
}
.news-thumb-ph {
  width: 88px;
  min-width: 88px;
  background: var(--bg-hover);
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 20px;
}
.news-body {
  padding: 9px 12px;
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 4px;
  min-width: 0;
}
.news-source {
  font-size: 10px;
  font-weight: 700;
  color: var(--accent);
  text-transform: uppercase;
  letter-spacing: .6px;
}
.news-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--text-head);
  line-height: 1.4;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.news-desc {
  font-size: 11px;
  color: var(--text-sub);
  line-height: 1.5;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.news-date { font-size: 10px; color: var(--text-dim); margin-top: auto; padding-top: 4px }
.no-news   { color: var(--text-dim); font-size: 13px; padding: 12px 0 }

@media (max-width: 860px) {
  .page-body  { grid-template-columns: 1fr; grid-template-rows: auto auto }
  body        { height: auto; overflow: auto }
  .right-panel{ grid-template-rows: auto auto }
  .left-panel, .news-pane { overflow-y: visible }
  .chart-wrap { height: 220px }
}
</style>
</head>
<body>

<header>
  <div>
    <h1>日本市場ダッシュボード</h1>
    <div class="header-sub" id="lastUpdated">読み込み中...</div>
  </div>
  <div class="header-right">
    <label class="theme-toggle">
      <input type="checkbox" id="themeToggle" onchange="toggleTheme()">
      <span class="toggle-track"><span class="toggle-thumb"></span></span>
      ライトモード
    </label>
    <button class="refresh-btn" onclick="location.reload()">⟳ 更新</button>
  </div>
</header>

<div class="page-body">

  <!-- ════════════ LEFT: MARKET PANEL ════════════ -->
  <div class="left-panel">

    <!-- PRICE CARDS -->
    <section>
      <div class="section-title">市場概況</div>
      <div class="cards-grid" id="cardsGrid">
        {% for s in stocks %}
        <div class="price-card" id="card-{{ loop.index0 }}"
             onclick="selectStock('{{ s.ticker }}','{{ s.name }}',{{ loop.index0 }})">
          <div class="card-name">{{ s.name }}</div>
          <div class="card-ticker">{{ s.ticker }}</div>
          <div class="card-price"  id="price-{{ loop.index0 }}">—</div>
          <div class="card-change" id="change-{{ loop.index0 }}">—</div>
          <div class="mini-chart"><canvas id="mini-{{ loop.index0 }}"></canvas></div>
        </div>
        {% endfor %}
      </div>
    </section>

    <!-- MAIN CHART -->
    <section>
      <div class="section-title">チャート</div>
      <div class="main-chart-box">
        <div class="chart-header">
          <div>
            <div class="chart-title"    id="chartTitle">日経平均</div>
            <div class="chart-subtitle" id="chartSubtitle">読み込み中...</div>
          </div>
          <div class="period-btns">
            {% for p, label in period_labels.items() %}
            <button class="period-btn {% if p == '1M' %}active{% endif %}"
                    data-period="{{ p }}"
                    onclick="setPeriod('{{ p }}')">{{ label }}</button>
            {% endfor %}
          </div>
        </div>
        <div class="chart-wrap"><canvas id="mainChart"></canvas></div>
      </div>
    </section>

  </div><!-- /left-panel -->

  <!-- ════════════ RIGHT: NEWS PANEL ════════════ -->
  <div class="right-panel">

    <!-- TOP-RIGHT: DOMESTIC NEWS -->
    <div class="news-pane">
      <div class="section-title">国内ニュース</div>
      <div class="news-list">
        {% for a in domestic_news %}
        <div class="news-card">
          <a href="{{ a.link }}" target="_blank" rel="noopener">
            {% if a.img %}
            <img class="news-thumb" src="{{ a.img }}" alt="" loading="lazy"
                 onerror="this.style.display='none'">
            {% else %}
            <div class="news-thumb-ph">{{ {'NHK 経済':'📊','NHK 社会':'📰'}.get(a.source,'🗞️') }}</div>
            {% endif %}
            <div class="news-body">
              <div class="news-source">{{ a.source }}</div>
              <div class="news-title">{{ a.title }}</div>
              <div class="news-desc">{{ a.desc }}</div>
              <div class="news-date">{{ a.pub }}</div>
            </div>
          </a>
        </div>
        {% endfor %}
        {% if not domestic_news %}
        <div class="no-news">国内ニュースを取得できませんでした</div>
        {% endif %}
      </div>
    </div>

    <!-- BOTTOM-RIGHT: OVERSEAS NEWS -->
    <div class="news-pane">
      <div class="section-title">海外ニュース</div>
      <div class="news-list">
        {% for a in overseas_news %}
        <div class="news-card">
          <a href="{{ a.link }}" target="_blank" rel="noopener">
            {% if a.img %}
            <img class="news-thumb" src="{{ a.img }}" alt="" loading="lazy"
                 onerror="this.style.display='none'">
            {% else %}
            <div class="news-thumb-ph">{{ {'MarketWatch':'📈','Reuters':'🌐','BBC':'📰'}.get(a.source,'📊') }}</div>
            {% endif %}
            <div class="news-body">
              <div class="news-source">{{ a.source }}</div>
              <div class="news-title">{{ a.title }}</div>
              <div class="news-desc">{{ a.desc }}</div>
              <div class="news-date">{{ a.pub }}</div>
            </div>
          </a>
        </div>
        {% endfor %}
        {% if not overseas_news %}
        <div class="no-news">海外ニュースを取得できませんでした</div>
        {% endif %}
      </div>
    </div>

  </div><!-- /right-panel -->

</div><!-- /page-body -->

<script>
const STOCKS = {{ stocks_js|safe }};
let currentTicker = "^N225";
let currentPeriod = "1M";
let activeCardIdx = 0;
let mainChartObj  = null;
const miniCharts  = {};

// ── Theme helpers ─────────────────────────────────────────
function isLight() { return document.body.classList.contains('light'); }

function chartTheme() {
  const l = isLight();
  return {
    grid:     l ? '#eaeef2' : '#161b22',
    tick:     l ? '#8c959f' : '#484f58',
    tipBg:    l ? '#ffffff' : '#161b22',
    tipBdr:   l ? '#d0d7de' : '#30363d',
    tipTitle: l ? '#57606a' : '#8b949e',
    tipBody:  l ? '#1f2328' : '#f0f6fc',
  };
}

function toggleTheme() {
  const light = document.getElementById('themeToggle').checked;
  document.body.classList.toggle('light', light);
  applyChartTheme();
}

function applyChartTheme() {
  if (!mainChartObj) return;
  const t  = chartTheme();
  const sc = mainChartObj.options.scales;
  sc.x.grid.color   = t.grid;
  sc.x.ticks.color  = t.tick;
  sc.x.border.color = t.tipBdr;
  sc.y.grid.color   = t.grid;
  sc.y.ticks.color  = t.tick;
  sc.y.border.color = t.tipBdr;
  const tp = mainChartObj.options.plugins.tooltip;
  tp.backgroundColor = t.tipBg;
  tp.borderColor     = t.tipBdr;
  tp.titleColor      = t.tipTitle;
  tp.bodyColor       = t.tipBody;
  mainChartObj.update();
}

// ── Colour helpers ────────────────────────────────────────
function lineColor(pos) { return pos ? '#3fb950' : '#f85149'; }
function fillColor(pos) { return pos ? 'rgba(63,185,80,.12)' : 'rgba(248,81,73,.12)'; }

// ── Main chart ────────────────────────────────────────────
async function loadMainChart(ticker, period) {
  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/${period}`);
  if (!res.ok) return;
  const d = await res.json();
  if (d.error) return;

  const color = lineColor(d.positive);
  const fill  = fillColor(d.positive);
  const sign  = d.positive ? '+' : '';
  const t     = chartTheme();

  document.getElementById('chartSubtitle').textContent =
    `${period}  ${sign}${d.change_pct}%`;

  const ctx = document.getElementById('mainChart').getContext('2d');
  if (mainChartObj) mainChartObj.destroy();
  mainChartObj = new Chart(ctx, {
    type: 'line',
    data: {
      labels: d.labels,
      datasets: [{
        data: d.prices,
        borderColor: color,
        backgroundColor: fill,
        borderWidth: 2,
        pointRadius: 0,
        fill: true,
        tension: 0.3
      }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      interaction: { mode: 'index', intersect: false },
      plugins: {
        legend: { display: false },
        tooltip: {
          backgroundColor: t.tipBg,
          borderColor:     t.tipBdr,
          borderWidth:     1,
          titleColor:      t.tipTitle,
          bodyColor:       t.tipBody,
          padding:         10,
          callbacks: { label: c => ' ' + c.parsed.y.toLocaleString() }
        }
      },
      scales: {
        x: {
          grid:   { color: t.grid },
          ticks:  { color: t.tick, maxTicksLimit: 8, font: { size: 11 } },
          border: { color: t.tipBdr }
        },
        y: {
          grid:     { color: t.grid },
          ticks:    { color: t.tick, font: { size: 11 }, callback: v => v.toLocaleString() },
          border:   { color: t.tipBdr },
          position: 'right'
        }
      }
    }
  });
}

// ── Mini sparkline ────────────────────────────────────────
async function loadMiniChart(ticker, idx) {
  const res = await fetch(`/api/chart/${encodeURIComponent(ticker)}/1M`);
  if (!res.ok) return;
  const d = await res.json();
  if (d.error || !d.prices) return;

  const color = lineColor(d.positive);
  const ctx   = document.getElementById(`mini-${idx}`).getContext('2d');
  if (miniCharts[idx]) miniCharts[idx].destroy();
  miniCharts[idx] = new Chart(ctx, {
    type: 'line',
    data: {
      labels: d.labels,
      datasets: [{ data: d.prices, borderColor: color, borderWidth: 1.5,
                   pointRadius: 0, fill: false, tension: 0.3 }]
    },
    options: {
      responsive: true,
      maintainAspectRatio: false,
      plugins: { legend: { display: false }, tooltip: { enabled: false } },
      scales:  { x: { display: false }, y: { display: false } },
      animation: { duration: 400 }
    }
  });
}

// ── Prices ────────────────────────────────────────────────
async function loadPrices() {
  const res  = await fetch('/api/prices');
  const data = await res.json();
  const now  = new Date().toLocaleTimeString('ja-JP');
  document.getElementById('lastUpdated').textContent = '最終更新：' + now;

  data.forEach((s, i) => {
    const priceEl  = document.getElementById(`price-${i}`);
    const changeEl = document.getElementById(`change-${i}`);
    if (!priceEl) return;

    if (s.price !== null) {
      priceEl.textContent = s.price.toLocaleString();
      if (s.change !== null) {
        const sign = s.positive ? '+' : '';
        changeEl.textContent = `${sign}${s.change} (${sign}${s.change_pct}%)`;
        changeEl.className = 'card-change ' + (s.positive ? 'up' : 'down');
        priceEl.className  = 'card-price '  + (s.positive ? 'up' : 'down');
      }
    } else {
      priceEl.textContent  = 'N/A';
      changeEl.textContent = '—';
    }
    setTimeout(() => loadMiniChart(s.ticker, i), i * 120);
  });
}

// ── Stock selection ───────────────────────────────────────
function selectStock(ticker, name, idx) {
  document.querySelectorAll('.price-card').forEach(c => c.classList.remove('active'));
  document.getElementById(`card-${idx}`).classList.add('active');
  document.getElementById('chartTitle').textContent = name;
  currentTicker = ticker;
  activeCardIdx = idx;
  loadMainChart(ticker, currentPeriod);
}

// ── Period toggle ─────────────────────────────────────────
function setPeriod(p) {
  currentPeriod = p;
  document.querySelectorAll('.period-btn').forEach(b => {
    b.classList.toggle('active', b.dataset.period === p);
  });
  loadMainChart(currentTicker, currentPeriod);
}

// ── Init ──────────────────────────────────────────────────
document.getElementById('card-0').classList.add('active');
loadPrices();
loadMainChart('^N225', '1M');
</script>
</body>
</html>"""

@app.route("/")
