IB_MED_KW = [
    '株','market','市場','経済','economy','oil','原油','半導体','chip',
    '銀行','bank','finance','trade','輸出','energy','supply chain','nvidia','apple',
    'トヨタ','ソニー','invest','投資','nasdaq','dow','日経','topix','nikkei','yen',
