def score_impact(article):
    text = (article.get('title', '') + ' ' + article.get('desc', '')).lower()
    score = (sum(2 for kw in IB_HIGH_KW if kw in text)
           + sum(1 for kw in IB_MED_KW  if kw in text))
    if score >= 4:
        return 'high'
    elif score >= 1:
        return 'medium'
