      if (s.change !== null) {
        const sign = s.positive ? '+' : '';
        ce.textContent = `${sign}${s.change}  (${sign}${s.change_pct}%)`;
        ce.className = 'sc-change ' + (s.positive ? 'up' : 'down');
        pe.className = 'sc-price '  + (s.positive ? 'up' : 'down');
        cd.classList.add(s.positive ? 'up-card' : 'down-card');
