async function fetchAnalysis(el) {
  const title = el.dataset.title || '';
  const desc  = el.dataset.desc  || '';
  const size  = el.dataset.size  || 'large';
  if (!title) return;

  el.innerHTML = '<div class="ai-loading">AI分析中</div>';

  try {
