def _get_anthropic_client():
    """Return an Anthropic client, falling back to the Claude Code OAuth token."""
    api_key = os.environ.get("ANTHROPIC_API_KEY")
    if api_key:
        return anthropic.Anthropic(api_key=api_key)
    # Fall back to Claude Code OAuth credentials
    cred_path = pathlib.Path.home() / ".claude" / ".credentials.json"
    try:
        creds = _json.loads(cred_path.read_text(encoding="utf-8"))
        token = creds.get("claudeAiOauth", {}).get("accessToken", "")
        if token:
            return anthropic.Anthropic(auth_token=token)
    except Exception:
        pass
    return anthropic.Anthropic()  # will raise its own auth error

